import{_ as i,o as n,c as l,ag as r}from"./chunks/framework.DXGyWiRo.js";const t="/images/uebung034.jpg",g=JSON.parse('{"title":"Übung Lektion 22","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung22.md","filePath":"lektionen/uebung22.md"}'),a={name:"lektionen/uebung22.md"};function s(p,e,d,u,o,h){return n(),l("div",null,[...e[0]||(e[0]=[r('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-22" tabindex="-1">Übung Lektion 22 <a class="header-anchor" href="#ubung-lektion-22" aria-label="Permalink to &quot;Übung Lektion 22&quot;">​</a></h1><p>A) Bilden und übersetzen Sie das Absolutiv zu folgenden Verben:</p><ol><li>आप् आप्त्वा</li><li>प्राप् प्राप्य</li><li>समास् समास्य</li><li>आस् आसित्वा</li><li>समि समित्य</li><li>संस्कृ संस्कृत्य</li><li>कृ कृत्वा</li><li>गम् गत्वा</li><li>उपगम् (2 Formen) उपगत्य । उपगम्य</li><li>जि जित्वा</li><li>विजि विजित्य</li><li>तन् तत्वा</li><li>दह् दग्ध्वा</li><li>उपदिश् उपदिश्य</li><li>नी नीत्वा</li><li>पच् पक्त्वा</li><li>उपपद् उपपद्य</li><li>पा १ पीत्वा</li><li>प्रच्छ् पृष्ट्वा</li><li>बुध् बुद्ध्वा</li><li>सम्बुध् सम्बुध्य</li><li>भज् भक्त्वा</li><li>भू भूत्वा</li><li>प्रभू प्रभूय</li><li>मन् मत्वा</li><li>मुच् मुक्त्वा</li><li>विमुच् विमुच्य</li><li>मृ मृत्वा</li><li>यज् ईष्ट्वा</li><li>लभ् लब्ध्वा</li><li>उपलभ् उपलभ्य</li><li>वच् उक्त्वा</li><li>प्रवच् प्रोच्य</li><li>वद् उदित्वा</li><li>प्रवद् प्रोद्य</li><li>हन् हत्वा</li></ol><p>B) Übersetzen Sie und lösen Sie die Komposita in Sanskrit auf:</p><p>अन्नं पक्त्वा ब्राह्मणदास्यत्ति ॥१॥ ब्राह्मणस्य दासी । Die Dienerin des Brahmanen kochte Speise und isst nun.</p><p>इष्टदेवतापूजां कृत्वेन्द्रादिदेवान्सद्ब्राह्मणाः स्तुवन्ति ॥२॥ इष्टाया देवताया पूजां । इन्द्र आदिर्येषां तान्देवान् । सन्तो ब्राह्मणाः । Die guten Brahmanen verehrten ihre persönliche Gottheit und preisen nun Indra und die übrigen Götter.</p><p>प्रस्थाय रामः सपुत्रः सद्गुरुश्रवणर्थेन ब्राह्मणग्रामं गच्छति ॥३॥ पुत्रेण सह । सतो गुरोः श्रवणार्थेन । ब्राह्मणानां ग्रामम् । Rāma ist mit seinem Sohn aufgebrochen und geht ins Brahmanendorf, um den guten Meister zu hören.</p><p>अनिष्ट्वा नरो भगवद्भक्तिमात्रेणापि मोक्षमाप्नोति ॥४॥ Auch wenn er nie geopfert hat, erlangt ein Mensch allein durch Hingabe an den Ehrwürdigen (कृष्ण) Erlösung.</p><p>गृहगर्भं प्रविश्य ब्राह्मणपुत्रमुपस्थाय क्षत्रियशूरो वक्ति ॥५॥ गृहस्य गर्भम् । ब्राह्मणस्य पुत्रम् । क्षत्रिय एव शूरः । Der Kṣatriyaheld betritt das Innere des Hauses, stellte sich in ehrerbietiger Haltung vor den Sohn des Brahmanen und spricht.</p><p>सम्बुध्य दुःखाद्यार्यसत्यानि प्रोच्य सुगतो मोक्षमार्गेण नरान्नयति ॥६॥ दुःखमादिर्येषां तान्यार्याणि सत्यानि । सुष्टु गतः । मोक्षस्य मार्गेण । मोक्षं मार्गेण । Buddha (सुगत) ist zur Erkenntnis erwacht, hat die Wahrheit vom Leid und die übrigen edlen Wahrheiten verkündet und führt nun die Menschen auf dem Weg zur Erlösung.</p><p>मन्त्रं विस्मृत्य यजन्यज्ञदोषं करोति ॥७॥ यज्ञस्य दोषम् । Da er den Spruch vergessen hat macht der Opfernde einen Opferfehler.</p><p>धनं प्राप्य बुद्धमार्गभिक्षवो दुष्यन्ति ॥८॥ बुद्धस्य मार्गो मार्गो येषां ते भिक्षवः । Wenn Sie Geld bekommen, verderben Mönche, die den Weg Buddhas gehen.</p><p>अनार्यशत्रुभिः संगत्य नरसिंहा विजयन्ते ॥९॥ आनार्यैः शत्रुभिः । नराः सिंहा इव ।  Die löwengleiche Männer sind mit den Feinden, die keine Ārya sind, zusammengestoßen, und siegen vollkommen.</p><p>पुण्यं कृत्वा सत्यमेवोदित्वा नरो नरकं नोपपद्यते ॥१०॥</p><p>Wenn er verdienstvolles getan hat und nur die Wahrheit gesprochen hat, kommt ein Mensch in keine Hölle.</p><p>C) Machen Sie aus obigen Sätzen (außer Sätze 8 und 10) Passivkonstruktionen</p><p>अन्नं पक्त्वा ब्राह्मणदास्यत्ति ॥१॥ अन्नं पक्त्वा ब्राह्मणदास्याद्यते ॥१॥</p><p>इष्टदेवतापूजां कृत्वेन्द्रादिदेवान्सद्ब्राह्मणाः स्तुवन्ति ॥२॥ इष्टदेवतापूजां कृत्वेन्द्रादिदेवाः सद्ब्राह्मणैः स्तूयन्ते ॥२॥</p><p>प्रस्थाय रामः सपुत्रः सद्गुरुश्रवार्थेन ब्राह्मणग्रामं गच्छति ॥३॥ प्रस्थाय रामेण सपुत्रेण सद्गुरुश्रवणार्थेन ब्राह्मणग्रामं गम्यते ॥३॥</p><p>अनिष्ट्वा नरो भगवद्भक्तिमात्रेणापि मोक्षमाप्नोति ॥४॥ अनिष्ट्वा नरेण भगवद्भक्तिमात्रेणापि मोक्ष आप्यते ॥४॥</p><p>गृहगर्भं प्रविश्य ब्राह्मणपुत्रमुपस्थाय क्षत्रियशूरो वक्ति ॥५॥ गृहगर्भं प्रविश्य ब्राह्मणपुत्रमुपस्थाय क्षत्रियशूरेणोच्यते ॥५॥</p><p>सम्बुध्य दुःखाद्यार्यसत्यानि प्रोच्य सुगतो मोक्षमार्गेण नरान्नयति ॥६॥ सम्बुध्य  दुःखाद्यार्यसत्यानि प्रोच्य सुगतेन मोक्षमार्गेण नरा नीयन्ते ॥६॥</p><p>मन्त्रं विस्मृत्य यजन्यज्ञदोषं करोति ॥७॥ मन्त्रं विस्मृत्य यजता यज्ञदोषः क्रियते ॥७॥</p><p>अनार्यशत्रुभिः संगत्य नरसिंहा विजयन्ते ॥९॥ अनार्यशत्रुभिः संगत्य नरसिंहैर्विजीयते ॥९॥</p><p><img src="'+t+'" alt=""><br> Abb.: धनं प्राप्य बुद्धमार्गभिक्षवो दुष्यन्ति<br> Thailand<br> [Bildquelle: dbz885.-- <a href="http://www.flickr.com/photos/dibdabdebi/217939309/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dibdabdebi/217939309/</a>. -- Zugriff am 2008-12-23. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, share alike)]</p>',26)])])}const c=i(a,[["render",s]]);export{g as __pageData,c as default};
